// MARK: - Authentication Flow Tracker

final class AuthFlowTracker {
    
    private let logger = AnalyticsLogger.shared
    
    enum AuthEvent: String {
        case loginStarted = "login_started"
        case loginSuccess = "login_success"
        case loginFailed = "login_failed"
        case logoutStarted = "logout_started"
        case logoutSuccess = "logout_success"
        case tokenRefreshStarted = "token_refresh_started"
        case tokenRefreshSuccess = "token_refresh_success"
        case tokenRefreshFailed = "token_refresh_failed"
        case registrationStarted = "registration_started"
        case registrationSuccess = "registration_success"
        case registrationFailed = "registration_failed"
        case passwordResetRequested = "password_reset_requested"
        case passwordResetSuccess = "password_reset_success"
        case passwordResetFailed = "password_reset_failed"
        case mfaRequired = "mfa_required"
        case mfaSuccess = "mfa_success"
        case mfaFailed = "mfa_failed"
        case sessionExpired = "session_expired"
        case biometricAuthStarted = "biometric_auth_started"
        case biometricAuthSuccess = "biometric_auth_success"
        case biometricAuthFailed = "biometric_auth_failed"
    }
    
    func trackLogin(email: String, method: String = "email") {
        logger.info("Authentication: \(AuthEvent.loginStarted.rawValue)", category: .authentication, metadata: [
            "email": DataRedactor.redact(email, type: .email),
            "method": method
        ])
    }
    
    func trackLoginSuccess(userId: String, email: String) {
        logger.info("Authentication: \(AuthEvent.loginSuccess.rawValue)", category: .authentication, metadata: [
            "user_id": DataRedactor.redact(userId, type: .userId),
            "email": DataRedactor.redact(email, type: .email)
        ])
    }
    
    func trackLoginFailure(email: String, errorCode: Int, errorMessage: String) {
        logger.warning("Authentication: \(AuthEvent.loginFailed.rawValue)", category: .authentication, metadata: [
            "email": DataRedactor.redact(email, type: .email),
            "error_code": errorCode,
            "error_message": errorMessage
        ])
    }
    
    func trackLogout(userId: String, reason: String = "user_initiated") {
        logger.info("Authentication: \(AuthEvent.logoutStarted.rawValue)", category: .authentication, metadata: [
            "user_id": DataRedactor.redact(userId, type: .userId),
            "reason": reason
        ])
    }
    
    func trackTokenRefresh(success: Bool, userId: String? = nil, errorMessage: String? = nil) {
        let event: AuthEvent = success ? .tokenRefreshSuccess : .tokenRefreshFailed
        let level: LogLevel = success ? .debug : .warning
        
        var metadata: [String: Any] = ["success": success]
        if let userId = userId {
            metadata["user_id"] = DataRedactor.redact(userId, type: .userId)
        }
        if let errorMessage = errorMessage {
            metadata["error_message"] = errorMessage
        }
        
        logger.log(level, category: .authentication, message: "Authentication: \(event.rawValue)", metadata: metadata)
    }
    
    func trackRegistration(email: String, success: Bool, errorMessage: String? = nil) {
        let event: AuthEvent = success ? .registrationSuccess : .registrationFailed
        let level: LogLevel = success ? .info : .warning
        
        var metadata: [String: Any] = [
            "email": DataRedactor.redact(email, type: .email),
            "success": success
        ]
        if let errorMessage = errorMessage {
            metadata["error_message"] = errorMessage
        }
        
        logger.log(level, category: .authentication, message: "Authentication: \(event.rawValue)", metadata: metadata)
    }
    
    func trackSessionExpired(userId: String) {
        logger.warning("Authentication: \(AuthEvent.sessionExpired.rawValue)", category: .authentication, metadata: [
            "user_id": DataRedactor.redact(userId, type: .userId)
        ])
    }
    
    func trackMFA(event: AuthEvent, userId: String, method: String = "sms") {
        logger.info("Authentication: \(event.rawValue)", category: .authentication, metadata: [
            "user_id": DataRedactor.redact(userId, type: .userId),
            "mfa_method": method
        ])
    }
}

// MARK: - API Call Tracker

final class APICallTracker {
    
    private let logger = AnalyticsLogger.shared
    private var pendingRequests: [String: CFAbsoluteTime] = [:]
    private let queue = DispatchQueue(label: "com.app.analytics.apitracker")
    
    /// Tracks the start of an API request
    func trackRequest(
        requestId: String,
        method: String,
        url: String,
        headers: [String: String]? = nil,
        body: [String: Any]? = nil
    ) {
        queue.async {
            self.pendingRequests[requestId] = CFAbsoluteTimeGetCurrent()
        }
        
        // Scrub URL for sensitive query params
        let scrubbedURL = DataRedactor.scrubString(url)
        
        var metadata: [String: Any] = [
            "request_id": requestId,
            "method": method,
            "url": scrubbedURL
        ]
        
        if let headers = headers {
            // Scrub authorization headers
            var scrubbedHeaders = headers
            for key in headers.keys {
                let lowerKey = key.lowercased()
                if lowerKey == "authorization" || lowerKey == "x-api-key" || lowerKey == "cookie" {
                    scrubbedHeaders[key] = "[REDACTED]"
                }
            }
            metadata["headers"] = scrubbedHeaders
        }
        
        if let body = body {
            metadata["body"] = DataRedactor.scrubDictionary(body)
        }
        
        logger.debug("API Request: \(method) \(scrubbedURL)", category: .api, metadata: metadata)
    }
    
    /// Tracks the completion of an API response
    func trackResponse(
        requestId: String,
        statusCode: Int,
        url: String,
        responseBody: [String: Any]? = nil,
        error: Error? = nil
    ) {
        var duration: Double?
        queue.sync {
            if let startTime = pendingRequests.removeValue(forKey: requestId) {
                duration = CFAbsoluteTimeGetCurrent() - startTime
            }
        }
        
        let scrubbedURL = DataRedactor.scrubString(url)
        
        var metadata: [String: Any] = [
            "request_id": requestId,
            "status_code": statusCode,
            "url": scrubbedURL
        ]
        
        if let duration = duration {
            metadata["duration_ms"] = Int(duration * 1000)
        }
        
        if let responseBody = responseBody {
            metadata["response_body"] = DataRedactor.scrubDictionary(responseBody)
        }
        
        if let error = error {
            metadata["error"] = error.localizedDescription
        }
        
        let level: LogLevel
        let statusMessage: String
        
        switch statusCode {
        case 200..<300:
            level = .debug
            statusMessage = "API Response Success"
        case 401:
            level = .warning
            statusMessage = "API Response Unauthorized"
        case 403:
            level = .warning
            statusMessage = "API Response Forbidden"
        case 404:
            level = .warning
            statusMessage = "API Response Not Found"
        case 400..<500:
            level = .warning
            statusMessage = "API Response Client Error"
        case 500..<600:
            level = .error
            statusMessage = "API Response Server Error"
        default:
            level = .info
            statusMessage = "API Response"
        }
        
        logger.log(level, category: .api, message: "\(statusMessage): \(statusCode) \(scrubbedURL)", metadata: metadata)
    }
    
    /// Tracks a network-level failure (no response received)
    func trackNetworkFailure(requestId: String, url: String, error: Error) {
        queue.sync {
            _ = pendingRequests.removeValue(forKey: requestId)
        }
        
        let scrubbedURL = DataRedactor.scrubString(url)
        
        logger.error("API Network Failure: \(scrubbedURL)", category: .api, metadata: [
            "request_id": requestId,
            "url": scrubbedURL,
            "error": error.localizedDescription,
            "error_type": String(describing: type(of: error))
        ])
    }
}

// MARK: - User Data Change Tracker

final class UserDataTracker {
    
    private let logger = AnalyticsLogger.shared
    
    enum DataChangeType: String {
        case profileUpdate = "profile_update"
        case settingsChange = "settings_change"
        case preferencesUpdate = "preferences_update"
        case addressUpdate = "address_update"
        case paymentMethodAdded = "payment_method_added"
        case paymentMethodRemoved = "payment_method_removed"
        case notificationSettingsChanged = "notification_settings_changed"
        case accountDeletion = "account_deletion"
        case dataExport = "data_export"
    }
    
    func trackProfileUpdate(userId: String, fields: [String]) {
        // Only log which fields changed, never the values
        logger.info("User data: \(DataChangeType.profileUpdate.rawValue)", category: .userData, metadata: [
            "user_id": DataRedactor.redact(userId, type: .userId),
            "updated_fields": fields,
            "field_count": fields.count
        ])
    }
    
    func trackSettingsChange(userId: String, setting: String, oldValue: String? = nil, newValue: String? = nil) {
        // For non-sensitive settings, we can log the values
        let nonSensitiveSettings: Set<String> = ["theme", "language", "timezone", "notifications_enabled", "font_size"]
        
        var metadata: [String: Any] = [
            "user_id": DataRedactor.redact(userId, type: .userId),
            "setting": setting
        ]
        
        if nonSensitiveSettings.contains(setting.lowercased()) {
            if let oldValue = oldValue { metadata["old_value"] = oldValue }
            if let newValue = newValue { metadata["new_value"] = newValue }
        } else {
            metadata["old_value"] = "[REDACTED]"
            metadata["new_value"] = "[REDACTED]"
        }
        
        logger.info("User data: \(DataChangeType.settingsChange.rawValue)", category: .userData, metadata: metadata)
    }
    
    func trackPaymentMethodChange(userId: String, action: DataChangeType, cardType: String? = nil) {
        var metadata: [String: Any] = [
            "user_id": DataRedactor.redact(userId, type: .userId),
            "action": action.rawValue
        ]
        if let cardType = cardType {
            metadata["card_type"] = cardType // e.g., "visa", "mastercard" — not sensitive
        }
        
        logger.info("User data: \(action.rawValue)", category: .userData, metadata: metadata)
    }
    
    func trackAccountDeletion(userId: String) {
        logger.warning("User data: \(DataChangeType.accountDeletion.rawValue)", category: .userData, metadata: [
            "user_id": DataRedactor.redact(userId, type: .userId)
        ])
    }
}

// MARK: - Error Tracker

final class ErrorTracker {
    
    private let logger = AnalyticsLogger.shared
    
    enum ErrorSeverity: String {
        case low = "low"
        case medium = "medium"
        case high = "high"
        case critical = "critical"
    }
    
    struct ErrorContext {
        let domain: String
        let code: Int
        let message: String
        let severity: ErrorSeverity
        let userId: String?
        let additionalInfo: [String: Any]?
        
        init(domain: String, code: Int, message: String, severity: ErrorSeverity = .medium,
             userId: String? = nil, additionalInfo: [String: Any]? = nil) {
            self.domain = domain
            self.code = code
            self.message = message
            self.severity = severity
            self.userId = userId
            self.additionalInfo = additionalInfo
        }
    }
    
    func trackError(_ context: ErrorContext, file: String = #file, function: String = #function, line: Int = #line) {
        var metadata: [String: Any] = [
            "error_domain": context.domain,
            "error_code": context.code,
            "error_message": DataRedactor.scrubString(context.message),
            "severity": context.severity.rawValue
        ]
        
        if let userId = context.userId {
            metadata["user_id"] = DataRedactor.redact(userId, type: .userId)
        }
        
        if let additionalInfo = context.additionalInfo {
            metadata["additional_info"] = DataRedactor.scrubDictionary(additionalInfo)
        }
        
        let level: LogLevel
        switch context.severity {
        case .low:      level = .warning
        case .medium:   level = .error
        case .high:     level = .error
        case .critical: level = .critical
        }
        
        logger.log(level, category: .error, message: "Error [\(context.domain):\(context.code)] \(DataRedactor.scrubString(context.message))",
                   metadata: metadata, file: file, function: function, line: line)
    }
    
    func trackSwiftError(_ error: Error, severity: ErrorSeverity = .medium, userId: String? = nil,
                         file: String = #file, function: String = #function, line: Int = #line) {
        let nsError = error as NSError
        let context = ErrorContext(
            domain: nsError.domain,
            code: nsError.code,
            message: nsError.localizedDescription,
            severity: severity,
            userId: userId,
            additionalInfo: nsError.userInfo.isEmpty ? nil : nsError.userInfo.mapValues { "\($0)" } as [String: Any]
        )
        trackError(context, file: file, function: function, line: line)
    }
    
    func trackCrashContext(userId: String?, lastScreen: String?, lastAction: String?) {
        var metadata: [String: Any] = [:]
        if let userId = userId {
            metadata["user_id"] = DataRedactor.redact(userId, type: .userId)
        }
        if let lastScreen = lastScreen {
            metadata["last_screen"] = lastScreen
        }
        if let lastAction = lastAction {
            metadata["last_action"] = lastAction
        }
        metadata["memory_usage_mb"] = ProcessInfo.processInfo.physicalMemory / (1024 * 1024)
        metadata["os_version"] = ProcessInfo.processInfo.operatingSystemVersionString
        
        logger.critical("Crash context captured", category: .error, metadata: metadata)
    }
}

// MARK: - Navigation / Interaction Tracker

final class InteractionTracker {
    
    private let logger = AnalyticsLogger.shared
    
    func trackScreenView(screenName: String, userId: String? = nil) {
        var metadata: [String: Any] = ["screen": screenName]
        if let userId = userId {
            metadata["user_id"] = DataRedactor.redact(userId, type: .userId)
        }
        logger.info("Screen viewed: \(screenName)", category: .navigation, metadata: metadata)
    }
    
    func trackButtonTap(buttonName: String, screenName: String) {
        logger.debug("Button tapped: \(buttonName)", category: .analytics, metadata: [
            "button": buttonName,
            "screen": screenName
        ])
    }
    
    func trackUserAction(action: String, details: [String: Any]? = nil) {
        let scrubbedDetails = details.map { DataRedactor.scrubDictionary($0) }
        logger.info("User action: \(action)", category: .analytics, metadata: scrubbedDetails)
    }
    
    func trackAppLifecycle(event: String) {
        logger.info("App lifecycle: \(event)", category: .lifecycle, metadata: [
            "event": event,
            "timestamp": Date().timeIntervalSince1970
        ])
    }
}

// MARK: - Performance Tracker

final class PerformanceTracker {
    
    private let logger = AnalyticsLogger.shared
    private var timers: [String: CFAbsoluteTime] = [:]
    private let queue = DispatchQueue(label: "com.app.analytics.perf")
    
    func startTimer(_ name: String) {
        queue.async {
            self.timers[name] = CFAbsoluteTimeGetCurrent()
        }
    }
    
    func stopTimer(_ name: String, metadata: [String: Any]? = nil) {
        var duration: Double?
        queue.sync {
            if let start = timers.removeValue(forKey: name) {
                duration = CFAbsoluteTimeGetCurrent() - start
            }
        }
        
        guard let elapsed = duration else {
            logger.warning("Performance timer '\(name)' was not started", category: .performance)
            return
        }
        
        var meta: [String: Any] = metadata ?? [:]
        meta["timer_name"] = name
        meta["duration_ms"] = Int(elapsed * 1000)
        
        let level: LogLevel = elapsed > 3.0 ? .warning : .debug
        logger.log(level, category: .performance, message: "Timer '\(name)': \(Int(elapsed * 1000))ms", metadata: meta)
    }
    
    func trackMemoryUsage(context: String = "") {
        var info = mach_task_basic_info()
        var count = mach_msg_type_number_t(MemoryLayout<mach_task_basic_info>.size) / 4
        let result = withUnsafeMutablePointer(to: &info) {
            $0.withMemoryRebound(to: integer_t.self, capacity: Int(count)) {
                task_info(mach_task_self_, task_flavor_t(MACH_TASK_BASIC_INFO), $0, &count)
            }
        }
        
        if result == KERN_SUCCESS {
            let usedMB = Double(info.resident_size) / (1024 * 1024)
            logger.debug("Memory usage: \(String(format: "%.1f", usedMB))MB", category: .performance, metadata: [
                "memory_mb": usedMB,
                "context": context
            ])
        }
    }
}

// MARK: - Secure Local Storage for Analytics

final class SecureAnalyticsStorage {
    
    private let logger = AnalyticsLogger.shared
    private let userDefaults: UserDefaults
    private let queue = DispatchQueue(label: "com.app.analytics.storage")
    
    // Store only non-sensitive analytics data
    private let analyticsKey = "com.app.analytics.events"
    private let maxStoredEvents = 1000
    
    init(suiteName: String? = nil) {
        self.userDefaults = suiteName.flatMap { UserDefaults(suiteName: $0) } ?? .standard
    }
    
    /// Stores an analytics event locally (scrubbed of sensitive data)
    func storeEvent(name: String, category: LogCategory, metadata: [String: Any]? = nil) {
        queue.async { [weak self] in
            guard let self = self else { return }
            
            var events = self.loadEvents()
            
            let scrubbedMetadata = metadata.map { DataRedactor.scrubDictionary($0) }
            
            let event: [String: Any] = [
                "name": name,
                "category": category.rawValue,
                "timestamp": Date().timeIntervalSince1970,
                "metadata": scrubbedMetadata ?? [:]
            ]
            
            events.append(event)
            
            // Trim to max size
            if events.count > self.maxStoredEvents {
                events = Array(events.suffix(self.maxStoredEvents))
            }
            
            self.userDefaults.set(events, forKey: self.analyticsKey)
        }
    }
    
    func loadEvents() -> [[String: Any]] {
        return userDefaults.array(forKey: analyticsKey) as? [[String: Any]] ?? []
    }
    
    func clearEvents() {
        queue.async { [weak self] in
            self?.userDefaults.removeObject(forKey: self?.analyticsKey ?? "")
        }
    }
    
    /// Exports events for sending to analytics backend
    func exportAndClear() -> [[String: Any]] {
        var events: [[String: Any]] = []
        queue.sync {
            events = loadEvents()
        }
        clearEvents()
        logger.debug("Exported \(events.count) analytics events", category: .storage)
        return events
    }
}

// MARK: - Main Analytics Module Facade

final class AnalyticsModule {
    
    static let shared = AnalyticsModule()
    
    let logger = AnalyticsLogger.shared
    let authTracker = AuthFlowTracker()
    let apiTracker = APICallTracker()
    let userDataTracker = UserDataTracker()
    let errorTracker = ErrorTracker()
    let interactionTracker = InteractionTracker()
    let performanceTracker = PerformanceTracker()
    let storage = SecureAnalyticsStorage()
    
    private init() {}
    
    /// Call during app launch
    func initialize() {
        interactionTracker.trackAppLifecycle(event: "app_launched")
        performanceTracker.startTimer("app_startup")
        
        logger.info("Analytics module initialized", category: .lifecycle, metadata: [
            "app_version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            "build": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "unknown",
            "os_version": ProcessInfo.processInfo.operatingSystemVersionString
        ])
    }
    
    /// Call when app startup is complete (e.g., first screen rendered)
    func startupComplete() {
        performanceTracker.stopTimer("app_startup")
    }
}

// MARK: - URLSession Extension for Automatic API Tracking

extension URLSession {
    
    func trackedDataTask(
        with request: URLRequest,
        requestId: String = UUID().uuidString,
        completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void
    ) -> URLSessionDataTask {
        
        let tracker = AnalyticsModule.shared.apiTracker
        let urlString = request.url?.absoluteString ?? "unknown"
        let method = request.httpMethod ?? "GET"
        
        // Parse request body if JSON
        var requestBody: [String: Any]?
        if let bodyData = request.httpBody,
           let json = try? JSONSerialization.jsonObject(with: bodyData) as? [String: Any] {
            requestBody = json
        }
        
        // Convert headers
        var headers: [String: String]?
        if let allHeaders = request.allHTTPHeaderFields {
            headers = allHeaders
        }
        
        tracker.trackRequest(requestId: requestId, method: method, url: urlString, headers: headers, body: requestBody)
        
        return dataTask(with: request) { data, response, error in
            if let error = error {
                tracker.trackNetworkFailure(requestId: requestId, url: urlString, error: error)
            } else if let httpResponse = response as? HTTPURLResponse {
                var responseBody: [String: Any]?
                if let data = data,
                   let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] {
                    responseBody = json
                }
                tracker.trackResponse(
                    requestId: requestId,
                    statusCode: httpResponse.statusCode,
                    url: urlString,
                    responseBody: responseBody,
                    error: error
                )
            }
            
            completionHandler(data, response, error)
        }
    }
}

